const fs = require('fs');
const path = require('path');

const validFileTypes = ['org', 'md', 'markdown', 'txt', 'html', 'xml', 'pdf', 'jpg', 'jpeg', 'png', 'webp', 'csv', 'json'];

function isSupportedFileType(filePath) {
  const fileExtension = filePath.split('.').pop().toLowerCase();
  return validFileTypes.includes(fileExtension);
}

function processDirectory(folder) {
  let filesToPush = [];
  try {
    const files = fs.readdirSync(folder, { withFileTypes: true });
    for (const file of files) {
      if (file.name.startsWith('.')) continue;
      const filePath = path.join(file.path, file.name || '');
      if (file.isFile() && isSupportedFileType(filePath)) {
        filesToPush.push(filePath);
      }
      if (file.isDirectory()) {
        filesToPush = filesToPush.concat(processDirectory(filePath));
      }
    }
  } catch (err) {
    console.error(`Error reading directory: ${err.message}`);
  }
  return filesToPush;
}

return { filesToPush };

const fs = require('fs');

const binaryFileTypes = ['pdf', 'jpg', 'jpeg', 'png', 'webp'];

function filenameToMimeType(filename) {
  const extension = filename.split('.').pop();
  const mimeTypes = {
    'pdf': 'application/pdf',
    'png': 'image/png',
    'jpg': 'image/jpeg',
    'jpeg': 'image/jpeg',
    'webp': 'image/webp',
    'md': 'text/markdown',
    'markdown': 'text/markdown',
    'org': 'text/org',
    'txt': 'text/plain',
    'html': 'text/html',
    'xml': 'application/xml',
    'json': 'application/json',
    'csv': 'text/csv'
  };
  return mimeTypes[extension] || 'text/plain';
}

const filesToPush = $input.all()[0].json.filesToPush || [];
const filesData = [];

for (const filePath of filesToPush) {
  try {
    const encoding = binaryFileTypes.includes(filePath.split('.').pop()) ? 'binary' : 'utf8';
    const mimeType = filenameToMimeType(filePath) + (encoding === 'utf8' ? '; charset=UTF-8' : '');
    const fileContent = fs.readFileSync(filePath, { encoding });
    filesData.push({
      path: filePath,
      mimeType: mimeType,
      content: fileContent,
      encoding: encoding
    });
  } catch (err) {
    console.error(`Error reading file ${filePath}: ${err.message}`);
  }
}

return { filesData };

const items = $input.all();
const successItems = items.filter(item => item.json.success === true);
const failedItems = items.filter(item => item.json.success === false);

return {
  syncStatus: 'completed',
  totalProcessed: items.length,
  successful: successItems.length,
  failed: failedItems.length,
  timestamp: new Date().toISOString()
};
